  #define	INP_RT_VALID		0x00000002 /* cached rtentry is valid */
+#define	INP_FREED		0x00000004 /* inp no more valid */

  #define	INPLOOKUP_WILDCARD	1
  #define	sotoinpcb(so)	((struct inpcb *)(so)->so_pcb)
